#include <stdio.h>

int countSquares(int n, int m, int arr[n][m]) {
    int dp[n][m];
    int sum = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = arr[i][j];
            } else if (arr[i][j] == 1) {
                dp[i][j] = 1 + (arr[i-1][j] < arr[i][j-1] ? (arr[i-1][j] < arr[i-1][j-1] ? arr[i-1][j] : arr[i-1][j-1]) : (arr[i][j-1] < arr[i-1][j-1] ? arr[i][j-1] : arr[i-1][j-1]));
            } else {
                dp[i][j] = 0;
            }
            sum += dp[i][j];
        }
    }
    return sum;
}

int main() {
    int n = 3, m = 4;
    int arr[n][m] = {{0, 1, 1, 1}, {1, 1, 1, 1}, {0, 1, 1, 1}};
    printf("The number of squares: %d\n", countSquares(n, m, arr));
    return 0;
}

